#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(b,c) for(int c=head[(b)];c;c=nxt[c])
using namespace std;const int QwQ=0;

//

inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;	
}
const int N=1e6+10,M=2e6+10,SN=2020;
int n,m;inline int FF(int x,int y){return x*(m+1)+y;}
int pre[N],ds[SN][SN];long long dp[SN][SN];

//

int head[N],des[M],nxt[M],val[M],cgt=1,g_stk[N],g_top,CGT,Head[N];
inline void ins(int x,int y,int z){nxt[++cgt]=head[x];des[head[x]=cgt]=y;val[cgt]=z;}
inline void tmp_ins(int x,int y,int z){nxt[++cgt]=head[x];g_stk[++g_top]=x;des[head[x]=cgt]=y;val[cgt]=z;}
inline void Save(){CGT=cgt;memcpy(Head,head,sizeof(head));}
inline void GoBack(){while(g_top){int q=g_stk[g_top--];head[q]=Head[q];}cgt=CGT;}

//

struct Sort
{
	int val, idx;inline Sort(int yy=0, int xx=0){val = xx; idx = yy;}
	inline bool operator < ( const Sort &Q ) const {return val > Q.val;}
};priority_queue<Sort> h; int dis[N];bool dij_vis[N];
inline void Dij(int s)
{
	memset(dij_vis,0,sizeof(dij_vis));memset(dis,0x3f,sizeof(dis));
	h.push(Sort(s,dis[s]=0));while(!h.empty())
	{
		int u=h.top().idx;h.pop();if(dij_vis[u])continue;dij_vis[u]=1;
		grep(u,i){int v=des[i];if(dis[u]+val[i]<dis[v])h.push(Sort(v,dis[v]=dis[u]+val[i]));}
	}
//	rep(1,20,i)printf("%d ",dis[i]);puts("");
}

//

struct Node
{
	int val,pos;bool col;inline Node(int xx=0,int yy=0,bool zz=0){val=xx;pos=yy;col=zz;}
	inline bool operator<(const Node &Q)const{return pos<Q.pos;}
}Q[N];

int V[SN],qwq;inline int Dit(int a,int b){return ds[a-qwq][b-qwq];}
inline void Solve()
{
	int qn=read();rep(0,qn-1,i)Q[i].val=read(),Q[i].pos=read(),Q[i].col=read();sort(Q,Q+qn);
	int Vtot=0,nn=qwq;Q[qn]=Q[0];
	rep(0,qn-1,i)
	{
		for(int j=Q[i].pos;j!=Q[i+1].pos;j=j%(2*n+2*m)+1)tmp_ins(nn,pre[j],0),tmp_ins(pre[j],nn,0);
		if(i+1<qn)tmp_ins(nn,nn+1,Q[i+1].val),tmp_ins(nn+1,nn,Q[i+1].val);
		else tmp_ins(nn,qwq,Q[i+1].val),tmp_ins(qwq,nn,Q[i+1].val);
		if(Q[i].col^Q[i+1].col)V[Vtot++]=nn;++nn;
	}
	if(Vtot==1)return puts("0"),void();
	rep(0,Vtot-1,i){Dij(V[i]);rep(0,Vtot-1,j)ds[V[i]-qwq][V[j]-qwq]=dis[V[j]];}
	memset(dp,0x3f,sizeof(dp));rep(0,Vtot-1,i)V[i+Vtot]=V[i];int len=Vtot<<1;
	rep(0,len-2,i)dp[i][i+1]=Dit(V[i],V[i+1]);
//	rep(0,len-1,i)printf("%d ",V[i]);puts("");
//	rep(0,Vtot-1,i){rep(0,Vtot-1,j)printf("%d ",Dit(V[i],V[j]));puts("");}
	for(int T=4;T<=Vtot;T+=2)
	{
		for(int l=0,r=T-1;r<len;++l,++r)
		{
			dp[l][r]=dp[l+1][r-1]+Dit(V[l],V[r]);
			for(int i=l+1;i<r-1;i+=2)dp[l][r]=min(dp[l][r],dp[l][i]+dp[i+1][r]);
		}
	}
	long long ans=4e18;for(int l=0,r=Vtot-1;r<len;++l,++r)ans=min(ans,dp[l][r]);
	printf("%lld\n",ans);GoBack();
}
int main()
{
	n=read();m=read();int T=read();qwq=(n+1)*(m+1);
	rep(1,n-1,i)rep(1,m,j){int x=FF(i,j-1),y=FF(i,j),z=read();ins(x,y,z);ins(y,x,z);}
	rep(1,n,i)rep(1,m-1,j){int x=FF(i-1,j),y=FF(i,j),z=read();ins(x,y,z);ins(y,x,z);}
	rep(1,m,i)pre[i]=FF(0,i);rep(m+1,m+n,i)pre[i]=FF(i-m,m);rep(m+n+1,2*m+n,i)pre[i]=FF(n,m-(i-m-n));rep(2*m+n+1,2*m+2*n,i)pre[i]=FF(n-(i-2*m-n),0);
	Save();while(T--)Solve();return 0-0;
}
